import React from 'react';
import { useAuth } from '../../context/AuthContext';
import { useNavigate, Outlet, Link, useLocation, Navigate } from 'react-router-dom';
import { LogOut, GraduationCap, LayoutDashboard, PlusCircle, User, Settings, Sparkles } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const DashboardLayout = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();

  if (!user) {
    return <Navigate to="/" replace />;
  }

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const navLinks = user.role === 'admin' 
    ? [
        { name: 'Overview', path: '/admin', icon: <LayoutDashboard size={20} /> },
        { name: 'New Task', path: '/admin/create', icon: <PlusCircle size={20} /> }
      ]
    : [
        { name: 'Dashboard', path: '/student', icon: <LayoutDashboard size={20} /> }
      ];

  return (
    <div className="min-h-screen bg-[#f8fafc] flex flex-col md:flex-row font-sans overflow-hidden">

      {/* ----------------- DESKTOP SIDEBAR ----------------- */}
      <aside className="hidden md:flex w-72 bg-white flex-shrink-0 flex-col pt-8 z-20 h-screen shadow-[4px_0_24px_rgba(0,0,0,0.02)] border-r border-slate-200/60 relative">
        <div className="flex items-center gap-3 px-8 mb-10">
          <div className="w-10 h-10 bg-gradient-to-tr from-primary-500 to-emerald-400 rounded-xl flex items-center justify-center shadow-lg shadow-primary-500/20 relative overflow-hidden group">
             <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
             <GraduationCap className="text-white w-6 h-6 z-10" />
          </div>
          <h1 className="text-2xl font-black tracking-tight text-slate-900 leading-none">EduTrack.</h1>
        </div>

        <nav className="flex-1 px-4 space-y-1.5 relative">
          {navLinks.map((link) => {
            const isActive = location.pathname === link.path || (link.path !== '/admin' && link.path !== '/student' && location.pathname.startsWith(link.path));

            return (
              <Link
                key={link.name}
                to={link.path}
                className={`flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-300 font-bold tracking-wide text-sm relative z-10 group overflow-hidden ${isActive ? 'text-primary-700' : 'text-slate-500 hover:text-slate-900'}`}
              >
                {isActive && (
                  <motion.div 
                    layoutId="active-nav-bg"
                    className="absolute inset-0 bg-primary-50/80 rounded-xl border border-primary-100 z-0"
                    transition={{ type: "spring", stiffness: 400, damping: 30 }}
                  />
                )}
                <div className={`relative z-10 transition-colors duration-300 ${isActive ? 'text-primary-600' : 'text-slate-400 group-hover:text-slate-600'} transform group-hover:scale-110`}>
                  {link.icon}
                </div>
                <span className="relative z-10">{link.name}</span>
              </Link>
            )
          })}
        </nav>

        {/* User Card */}
        <div className="p-4 mt-auto">
          <div className="bg-slate-50 border border-slate-200/60 rounded-2xl p-4 flex items-center justify-between mb-3 shadow-sm hover:shadow-md transition-shadow cursor-default">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-white flex items-center justify-center text-slate-700 font-black text-lg border border-slate-200 shadow-sm relative overflow-hidden">
                <div className="absolute inset-0 bg-gradient-to-br from-transparent to-slate-50/50"></div>
                <span className="relative z-10">{user.name.charAt(0)}</span>
              </div>
              <div>
                <p className="text-sm font-bold text-slate-900 leading-tight">{user.name}</p>
                <div className="flex items-center gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                  <p className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">{user.role}</p>
                </div>
              </div>
            </div>
            <button className="text-slate-400 hover:text-primary-600 transition-colors transform hover:rotate-90 duration-300">
              <Settings size={18} />
            </button>
          </div>
          <button
            onClick={handleLogout}
            className="w-full flex items-center justify-center gap-2 px-4 py-3 text-sm font-bold text-slate-500 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-all duration-300 group"
          >
            <LogOut size={18} className="transform group-hover:-translate-x-1 duration-300" />
            Secure Sign Out
          </button>
        </div>
      </aside>

      {/* ----------------- MOBILE BRANDING HEADER ----------------- */}
      <div className="md:hidden flex items-center justify-between px-6 py-4 bg-white/80 backdrop-blur-md sticky top-0 z-30 border-b border-slate-200/60">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-gradient-to-tr from-primary-500 to-emerald-400 rounded-lg flex items-center justify-center shadow-lg shadow-primary-500/20">
             <GraduationCap className="text-white w-5 h-5" />
          </div>
          <h1 className="text-xl font-black tracking-tight text-slate-900">EduTrack.</h1>
        </div>
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-lg bg-slate-100 flex items-center justify-center text-slate-700 font-black border border-slate-200">
            {user.name.charAt(0)}
          </div>
        </div>
      </div>

      {/* ----------------- MAIN CONTENT AREA ----------------- */}
      <main className="flex-1 overflow-x-hidden w-full relative h-[100dvh] md:h-screen bg-slate-50">
        {/* Subtle grid background pattern */}
        <div className="absolute inset-0 bg-[linear-gradient(to_right,#8080800a_1px,transparent_1px),linear-gradient(to_bottom,#8080800a_1px,transparent_1px)] bg-[size:24px_24px] z-0 pointer-events-none"></div>
        <div className="absolute inset-0 bg-gradient-to-b from-white/40 to-transparent pointer-events-none z-0"></div>

        <div className="p-4 sm:p-6 md:p-8 lg:p-12 xl:p-16 max-w-7xl mx-auto w-full relative z-10 h-[calc(100dvh-70px)] md:h-full pb-28 md:pb-12 overflow-y-auto custom-scrollbar">
          <Outlet />
        </div>
      </main>

      {/* ----------------- MOBILE BOTTOM NAV ----------------- */}
      <div className="md:hidden fixed bottom-6 left-1/2 transform -translate-x-1/2 w-[90%] max-w-sm z-50">
        <div className="bg-slate-900/90 backdrop-blur-xl border border-white/20 shadow-2xl rounded-3xl p-2 flex items-center justify-between">
          {navLinks.map((link) => {
            const isActive = location.pathname === link.path || (link.path !== '/admin' && link.path !== '/student' && location.pathname.startsWith(link.path));

            return (
              <Link
                key={link.name}
                to={link.path}
                className={`flex-1 flex flex-col items-center justify-center py-2.5 rounded-2xl transition-all duration-300 relative z-10 ${isActive ? 'text-white' : 'text-slate-400 hover:text-slate-200'}`}
              >
                {isActive && (
                  <motion.div 
                    layoutId="mobile-active-bg"
                    className="absolute inset-0 bg-white/10 rounded-2xl z-0"
                    transition={{ type: "spring", stiffness: 400, damping: 30 }}
                  />
                )}
                <div className="relative z-10 mb-1">
                  {link.icon}
                </div>
                <span className="text-[10px] font-bold tracking-wider relative z-10">{link.name}</span>
              </Link>
            )
          })}

          <button
            onClick={handleLogout}
            className="flex-1 flex flex-col items-center justify-center py-2.5 text-slate-400 hover:text-rose-400 rounded-2xl transition-all duration-300"
          >
            <LogOut size={20} className="mb-1" />
            <span className="text-[10px] font-bold tracking-wider">Logout</span>
          </button>
        </div>
      </div>

    </div>
  );
};

export default DashboardLayout;

// Global auth state ΓÇö any component can call useAuth() to get the current user
import React, { createContext, useContext, useState, useEffect } from 'react';
import { getUsers, initializeData } from '../utils/localStorage';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [usersList, setUsersList] = useState([]);

  useEffect(() => {
    initializeData();              // seed DB on first load
    setUsersList(getUsers());      // load all users for login matching
  }, []);

  const login  = (id) => setUser(usersList.find(u => u.id === id) || null);
  const logout = ()   => setUser(null);

  return (
    <AuthContext.Provider value={{ user, usersList, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import {
  GraduationCap, ArrowRight, Lock, Mail, Users,
  UserCircle2, BookOpen, BarChart3, ShieldCheck,
  Sparkles, Zap, Star,
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import toast from 'react-hot-toast';

/* ΓöÇΓöÇ tiny floating stat card ΓöÇΓöÇ */
const StatPill = ({ icon, value, label, delay, className }) => (
  <motion.div
    initial={{ opacity: 0, scale: 0.8, y: 20 }}
    animate={{ opacity: 1, scale: 1, y: 0 }}
    transition={{ duration: 0.6, delay, ease: 'easeOut' }}
    className={`absolute flex items-center gap-2.5 px-4 py-2.5 rounded-2xl
      bg-white/8 backdrop-blur-md border border-white/15
      shadow-xl shadow-black/30 animate-float ${className}`}
  >
    <span className="text-xl">{icon}</span>
    <div>
      <p className="text-white font-black text-sm leading-none">{value}</p>
      <p className="text-white/50 text-[10px] mt-0.5">{label}</p>
    </div>
  </motion.div>
);

/* ΓöÇΓöÇ animated background grid dot ΓöÇΓöÇ */
const GridDot = ({ style }) => (
  <span
    className="absolute w-px h-px rounded-full bg-white/20"
    style={style}
  />
);

/* ΓöÇΓöÇ feature row ΓöÇΓöÇ */
const FEATURES = [
  { icon: BookOpen,    color: 'text-violet-400', bg: 'bg-violet-500/10 border-violet-500/20', text: 'Submit & track assignments with double-verify flow' },
  { icon: BarChart3,   color: 'text-sky-400',    bg: 'bg-sky-500/10 border-sky-500/20',       text: 'Real-time submission analytics for instructors' },
  { icon: ShieldCheck, color: 'text-emerald-400', bg: 'bg-emerald-500/10 border-emerald-500/20', text: 'Role-based access ΓÇö each user sees their own data' },
];

export default function Login() {
  const { login, usersList } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab]   = useState('student');
  const [email, setEmail]           = useState('');
  const [password, setPassword]     = useState('');
  const [isLoading, setIsLoading]   = useState(false);
  const [focused, setFocused]       = useState(null);

  const executeLogin = (role) => {
    setIsLoading(true);
    setTimeout(() => {
      const matched = usersList.find(u => u.role === role);
      if (matched) {
        login(matched.id);
        toast.success(`Welcome back, ${matched.name}! ≡ƒæï`);
        navigate(role === 'admin' ? '/admin' : '/student');
      } else {
        toast.error('No user found for this role.');
        setIsLoading(false);
      }
    }, 1200);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('Please fill in email and password.');
    executeLogin(activeTab);
  };


  return (
    <div className="min-h-[100dvh] md:h-[100dvh] bg-[#06040f] flex flex-col overflow-x-hidden md:overflow-hidden font-sans relative select-none">

      {/* ΓöÇΓöÇ Layered animated blobs ΓöÇΓöÇ */}
