          bg-violet-700 rounded-full blur-[160px] opacity-20 animate-blob" />
        {/* accent cyan blob */}
        <div className="absolute bottom-[-10%] right-[-10%] w-[60%] h-[60%]
          bg-sky-600 rounded-full blur-[180px] opacity-15 animate-blob-slow"
          style={{ animationDelay: '3s' }} />
        {/* pink accent */}
        <div className="absolute top-[40%] left-[30%] w-[40%] h-[40%]
          bg-fuchsia-800 rounded-full blur-[140px] opacity-10 animate-blob"
          style={{ animationDelay: '6s' }} />

        {/* subtle dot grid */}
        <svg className="absolute inset-0 w-full h-full opacity-[0.04]" xmlns="http://www.w3.org/2000/svg">
          <defs>
            <pattern id="dots" x="0" y="0" width="30" height="30" patternUnits="userSpaceOnUse">
              <circle cx="1" cy="1" r="1" fill="white" />
            </pattern>
          </defs>
          <rect width="100%" height="100%" fill="url(#dots)" />
        </svg>

        {/* diagonal lines */}
        <div className="absolute inset-0 opacity-[0.025]"
          style={{ backgroundImage: 'repeating-linear-gradient(45deg, white 0, white 1px, transparent 0, transparent 50%)', backgroundSize: '40px 40px' }} />
      </div>

      {/* ΓöÇΓöÇ Top nav bar ΓöÇΓöÇ */}
      <motion.nav
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
        className="absolute top-0 left-0 right-0 z-20 flex items-center justify-between px-5 sm:px-8 py-4 sm:py-5"
      >
        <div className="flex items-center gap-2.5">
          <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-violet-500 to-fuchsia-500
            flex items-center justify-center shadow-lg shadow-violet-500/40">
            <GraduationCap className="text-white w-5 h-5" />
          </div>
          <span className="text-white font-black text-lg tracking-tight">EduTrack<span className="text-violet-400">.</span></span>
        </div>

      </motion.nav>

      {/* ΓöÇΓöÇ Main content ΓöÇΓöÇ */}
      <div className="w-full flex flex-1 items-center relative z-10 overflow-x-hidden">

        {/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ LEFT PANEL ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */}
        <div className="hidden lg:flex lg:w-[54%] flex-col justify-center px-16 xl:px-24 h-full py-6 relative overflow-hidden">

          {/* floating stat pills */}
          <StatPill icon="≡ƒôÜ" value="1,240+"  label="Assignments tracked"  delay={0.8}  className="top-12 right-16 animate-float hidden xl:flex" />
          <StatPill icon="ΓÜí" value="99.9%"   label="Uptime guarantee"     delay={1.0}  className="bottom-24 right-4 animate-float-slow hidden xl:flex" style={{ animationDelay: '2s' }} />
          <StatPill icon="≡ƒÅå" value="4.9Γÿà"    label="Instructor rating"    delay={1.2}  className="bottom-48 left-0 animate-float hidden xl:flex" style={{ animationDelay: '4s' }} />

          {/* headline */}
          <motion.div
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
          >
            <div className="inline-flex items-center gap-2 mb-6 px-4 py-1.5 rounded-full
              bg-violet-500/10 border border-violet-500/30 text-violet-300 text-xs font-bold uppercase tracking-widest">
              <Sparkles size={11} />
              Assignment Management Platform
            </div>

            <h2 className="text-4xl xl:text-6xl 2xl:text-7xl font-black leading-[1.05] text-white tracking-tight mb-6">
              The smartest<br />
              way to{' '}
              <span className="relative inline-block">
                <span className="relative z-10 text-transparent bg-clip-text"
                  style={{ backgroundImage: 'linear-gradient(135deg, #a78bfa 0%, #38bdf8 50%, #f472b6 100%)', backgroundSize: '200%', animation: 'shimmer 3s linear infinite' }}>
                  manage
                </span>
                {/* underline glow */}
                <span className="absolute bottom-0 left-0 right-0 h-px bg-gradient-to-r from-violet-400 via-sky-400 to-pink-400 opacity-70" />
              </span>
              <br />assignments.
            </h2>

            <p className="text-white/40 text-base xl:text-lg leading-relaxed max-w-md font-medium">
              Streamline assignment distribution, track student progress in real time,
              and manage your{' '}
              <span className="text-white/70">entire classroom workflow</span>{' '}
              from a single, unified platform.
            </p>
          </motion.div>

          {/* feature list */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.5, duration: 0.7 }}
            className="mt-10 space-y-4"
          >
            {FEATURES.map((f, i) => {
              const Icon = f.icon;
              return (
                <motion.div
                  key={i}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.6 + i * 0.15 }}
                  className="flex items-center gap-4 group"
                >
                  <div className={`w-9 h-9 rounded-xl border flex items-center justify-center shrink-0
                    ${f.bg} ${f.color} transition-transform duration-300 group-hover:scale-110`}>
                    <Icon size={16} />
