          >

            {/* Glass card */}
            <div className="relative rounded-3xl overflow-hidden p-5 sm:p-9"
              style={{
                background: 'linear-gradient(145deg, rgba(255,255,255,0.06) 0%, rgba(255,255,255,0.02) 100%)',
                border: '1px solid rgba(255,255,255,0.1)',
                boxShadow: '0 40px 80px rgba(0,0,0,0.5), 0 0 0 1px rgba(139,92,246,0.1), inset 0 1px 0 rgba(255,255,255,0.08)',
                backdropFilter: 'blur(24px)',
              }}
            >
              {/* top glow inside card */}
              <div className="absolute top-0 left-1/2 -translate-x-1/2 w-64 h-px
                bg-gradient-to-r from-transparent via-violet-400/60 to-transparent" />

              {/* Header */}
