                {/* sliding pill */}
                <motion.div
                  layout
                  transition={{ type: 'spring', stiffness: 400, damping: 34 }}
                  className="absolute inset-y-1.5 w-[calc(50%-6px)] rounded-xl
                    bg-gradient-to-r from-violet-600 to-violet-500
                    shadow-lg shadow-violet-600/40"
                  style={{ left: activeTab === 'student' ? '6px' : 'calc(50%)' }}
                />
                {[
                  ['student', GraduationCap, 'Student'],
                  ['admin',   Users,          'Instructor'],
                ].map(([role, Icon, label]) => (
                  <button
                    key={role}
                    onClick={() => setActiveTab(role)}
                    className={`w-1/2 py-2.5 text-sm font-bold flex items-center justify-center gap-2
                      relative z-10 transition-colors duration-200
                      ${activeTab === role ? 'text-white' : 'text-white/35 hover:text-white/70'}`}
                  >
                    <Icon size={15} />
                    {label}
                  </button>
                ))}
              </div>

              {/* Form */}
              <form onSubmit={handleSubmit} className="space-y-3 sm:space-y-4">

                {/* Email field */}
                <div className="space-y-1.5">
                  <label className="text-[11px] font-bold uppercase tracking-widest text-white/40">
                    Email Address
