                  <div
                    className="relative group rounded-2xl transition-all duration-300"
                    style={focused === 'email' ? {
                      boxShadow: '0 0 0 2px rgba(139,92,246,0.5)',
                    } : {}}
                  >
                    <Mail size={15} className={`absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none transition-colors duration-200
                      ${focused === 'email' ? 'text-violet-400' : 'text-white/20'}`} />
                    <input
                      type="email"
                      required
                      value={email}
                      onChange={e => setEmail(e.target.value)}
                      onFocus={() => setFocused('email')}
                      onBlur={() => setFocused(null)}
                      placeholder={activeTab === 'student' ? 'alice@student.edu' : 'dr.smith@university.edu'}
                      className="w-full bg-white/[0.05] border border-white/8 text-white text-sm
                        rounded-2xl pl-11 pr-4 py-3 sm:py-3.5 outline-none
                        placeholder:text-white/20 transition-all duration-200
                        focus:border-violet-500/60 focus:bg-white/[0.07]"
                    />
                  </div>
                </div>

                {/* Password field */}
                <div className="space-y-1.5">
                  <label className="block mb-1.5 text-[11px] font-bold uppercase tracking-widest text-white/40">
                    Password
                  </label>
                  <div
                    className="relative group rounded-2xl transition-all duration-300"
                    style={focused === 'pass' ? {
                      boxShadow: '0 0 0 2px rgba(139,92,246,0.5)',
                    } : {}}
                  >
                    <Lock size={15} className={`absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none transition-colors duration-200
                      ${focused === 'pass' ? 'text-violet-400' : 'text-white/20'}`} />
                    <input
                      type="password"
                      required
                      value={password}
                      onChange={e => setPassword(e.target.value)}
                      onFocus={() => setFocused('pass')}
                      onBlur={() => setFocused(null)}
                      placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
