import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { getAssignmentsByAdmin, getAssignmentSubmissions, getUsers } from '../../utils/localStorage';
import { Link } from 'react-router-dom';
import { PlusCircle, Users, CheckCircle2, Circle, Clock, ChevronDown, BarChart3, FileBadge, GraduationCap, RefreshCw, CalendarPlus } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const AdminDashboard = () => {
  const { user } = useAuth();
  const [assignments, setAssignments] = useState([]);
  const [students, setStudents] = useState([]);
  const [expandedId, setExpandedId] = useState(null);

  const loadData = React.useCallback(() => {
    const adminAssignments = getAssignmentsByAdmin(user.id);
    adminAssignments.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));

    const enriched = adminAssignments.map(assignment => {
      const subs = getAssignmentSubmissions(assignment.id);
      return { ...assignment, submissions: subs };
    });

    setAssignments(enriched);
    const allUsers = getUsers();
    setStudents(allUsers.filter(u => u.role === 'student'));
  }, [user.id]);

  useEffect(() => {
    loadData();

    // Re-sync when the admin tab regains focus (e.g. student submitted in another tab)
    const onVisible = () => { if (document.visibilityState === 'visible') loadData(); };
    document.addEventListener('visibilitychange', onVisible);
    window.addEventListener('focus', loadData);

    return () => {
      document.removeEventListener('visibilitychange', onVisible);
      window.removeEventListener('focus', loadData);
    };
  }, [loadData]);

  const toggleExpand = (id) => setExpandedId(expandedId === id ? null : id);

  // Quick Stats
  const totalAssignments = assignments.length;
  const totalSubmissions = assignments.reduce((acc, curr) => acc + curr.submissions.filter(s => s.status === 'submitted').length, 0);
  const possibleSubmissions = totalAssignments * students.length;
  const overallCompletion = possibleSubmissions === 0 ? 0 : Math.round((totalSubmissions / possibleSubmissions) * 100);

  const containerVariants = {
    hidden: { opacity: 0 },
    show: { opacity: 1, transition: { staggerChildren: 0.1 } }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 30 },
    show: { opacity: 1, y: 0, transition: { type: "spring", stiffness: 300, damping: 24 } }
  };

  return (
    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.5 }} className="space-y-10 font-sans">

      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-6">
        <div>
          <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: 0.1 }} className="flex items-center gap-2 mb-2">
            <GraduationCap className="text-primary-500 w-5 h-5" />
            <span className="text-primary-600 font-bold uppercase tracking-widest text-sm">Instructor Hub</span>
          </motion.div>
          <h2 className="text-3xl sm:text-4xl lg:text-5xl font-black text-slate-900 tracking-tight leading-tight">
            Dashboard Overview
          </h2>
        </div>
      <div className="flex items-center gap-3">
          <motion.button
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95, rotate: 180 }}
            onClick={loadData}
            title="Refresh submissions"
            className="inline-flex items-center justify-center w-11 h-11 bg-white border border-slate-200 text-slate-500 hover:text-slate-800 hover:border-slate-300 rounded-2xl transition-all shadow-sm hover:shadow"
          >
            <RefreshCw size={18} />
          </motion.button>
          <Link
            to="/admin/create"
            className="inline-flex items-center justify-center px-6 py-3.5 bg-slate-900 hover:bg-slate-800 text-white font-bold rounded-2xl transition-all shadow-lg hover:shadow-xl hover:-translate-y-1"
          >
            <PlusCircle size={20} className="mr-2.5" />
            New Assignment
          </Link>
        </div>
      </div>

      {/* Stats Cards Row */}
      <motion.div variants={containerVariants} initial="hidden" animate="show" className="grid grid-cols-2 md:grid-cols-3 gap-4 sm:gap-6">
        <motion.div variants={itemVariants} className="bg-gradient-to-br from-white to-slate-50 p-6 sm:p-8 rounded-[1.5rem] sm:rounded-[2rem] border border-slate-200 shadow-sm hover:shadow-md transition-shadow relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-blue-100 rounded-full mix-blend-multiply filter blur-2xl opacity-50 transform translate-x-1/2 -translate-y-1/2 group-hover:scale-150 transition-transform duration-700"></div>
           <div className="w-14 h-14 bg-white rounded-2xl shadow-sm border border-slate-100 flex items-center justify-center mb-6 text-blue-600">
             <FileBadge size={28} />
           </div>
           <p className="text-sm font-bold text-slate-500 tracking-wider uppercase mb-2">Total Tasks Assigned</p>
           <p className="text-5xl font-black text-slate-900">{totalAssignments}</p>
        </motion.div>

        <motion.div variants={itemVariants} className="bg-gradient-to-br from-white to-slate-50 p-6 sm:p-8 rounded-[1.5rem] sm:rounded-[2rem] border border-slate-200 shadow-sm hover:shadow-md transition-shadow relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-100 rounded-full mix-blend-multiply filter blur-2xl opacity-50 transform translate-x-1/2 -translate-y-1/2 group-hover:scale-150 transition-transform duration-700"></div>
           <div className="w-14 h-14 bg-white rounded-2xl shadow-sm border border-slate-100 flex items-center justify-center mb-6 text-emerald-500">
             <CheckCircle2 size={28} />
           </div>
           <p className="text-sm font-bold text-slate-500 tracking-wider uppercase mb-2">Total Submissions</p>
           <p className="text-5xl font-black text-slate-900 tracking-tight">{totalSubmissions}</p>
           <p className="mt-2 text-sm font-semibold text-emerald-600">Out of {possibleSubmissions} possible</p>
        </motion.div>

        <motion.div variants={itemVariants} className="col-span-2 md:col-span-1 bg-gradient-to-br from-slate-900 to-slate-800 p-6 sm:p-8 rounded-[1.5rem] sm:rounded-[2rem] shadow-xl relative overflow-hidden group">
           <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 brightness-100 contrast-150 mix-blend-overlay"></div>
           <div className="absolute top-0 right-0 w-40 h-40 bg-primary-500 rounded-full mix-blend-screen filter blur-3xl opacity-30 transform translate-x-1/3 -translate-y-1/3 group-hover:opacity-50 transition-opacity duration-700"></div>
           <div className="w-14 h-14 bg-white/10 backdrop-blur-md rounded-2xl border border-white/10 flex items-center justify-center mb-6 text-primary-400">
             <BarChart3 size={28} />
           </div>
           <p className="text-sm font-bold text-slate-300 tracking-wider uppercase mb-2">Avg Completion</p>
           <p className="text-5xl font-black text-white">{overallCompletion}%</p>
           <div className="h-1.5 w-full bg-white/10 rounded-full mt-5 overflow-hidden">
             <motion.div 
               className="h-full bg-primary-500 rounded-full"
               initial={{ width: 0 }}
               animate={{ width: `${overallCompletion}%` }}
               transition={{ duration: 1.2, delay: 0.5 }}
             />
           </div>
        </motion.div>
      </motion.div>

      {/* Assignment List Area */}
      <div>
        <div className="flex items-center justify-between mb-6">
          <h3 className="text-2xl font-bold text-slate-900 tracking-tight">Assignment Analytics</h3>
          <span className="bg-slate-200 text-slate-700 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest">{assignments.length} Total</span>
        </div>

        <motion.div variants={containerVariants} initial="hidden" animate="show" className="space-y-6">
          {assignments.length === 0 ? (
            <motion.div variants={itemVariants} className="text-center p-20 bg-white rounded-[2rem] border border-dashed border-slate-300 shadow-sm">
              <div className="w-20 h-20 bg-slate-50 rounded-[2rem] flex items-center justify-center mx-auto mb-6 transform rotate-3">
                <PlusCircle className="h-10 w-10 text-slate-400 -rotate-3" />
              </div>
              <h3 className="text-2xl font-bold text-slate-900 mb-2">No assignments active</h3>
              <p className="text-slate-500 font-medium max-w-sm mx-auto mb-8">Deploy an assignment to your students and start tracking their analytics here.</p>
              <Link 
                to="/admin/create"
                className="inline-flex items-center px-6 py-3 bg-slate-900 hover:bg-slate-800 text-white font-bold rounded-xl transition-all shadow-md hover:-translate-y-0.5"
              >
                Create First Assignment
              </Link>
            </motion.div>
          ) : (
            assignments.map((assignment) => {
              const submittedCount = assignment.submissions.filter(s => s.status === 'submitted').length;
              const totalStudents = students.length;
              const progressPercent = totalStudents === 0 ? 0 : Math.round((submittedCount / totalStudents) * 100);
              const isExpanded = expandedId === assignment.id;

              return (
                <motion.div variants={itemVariants} layout key={assignment.id} className={`bg-white rounded-[2rem] border transition-all duration-300 overflow-hidden ${isExpanded ? 'border-primary-200 shadow-xl' : 'border-slate-200 shadow-sm hover:shadow-md hover:border-slate-300'}`}>

                  <div 
                    className="p-5 sm:p-8 cursor-pointer flex flex-col lg:flex-row lg:items-center justify-between gap-5 sm:gap-8 relative overflow-hidden"
                    onClick={() => toggleExpand(assignment.id)}
                  >
                    {isExpanded && <div className="absolute inset-0 bg-primary-50/30 z-0"></div>}

                    <div className="flex-1 relative z-10">
                      <div className="flex flex-wrap items-center gap-2 mb-3">
                         <h3 className="text-2xl font-bold text-slate-900 leading-tight w-full">{assignment.title}</h3>
                         <span className="px-3 py-1 rounded-full text-xs font-bold bg-slate-100 text-slate-600 flex items-center uppercase tracking-widest shrink-0">
                           <Clock size={12} className="mr-1.5" />
                           Due {new Date(assignment.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                         </span>
                         {assignment.createdAt && (
                           <span className="px-3 py-1 rounded-full text-xs font-bold bg-violet-50 text-violet-600 border border-violet-100 flex items-center uppercase tracking-widest shrink-0">
                             <CalendarPlus size={12} className="mr-1.5" />
                             Posted {new Date(assignment.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                           </span>
                         )}
                      </div>
                      <p className="text-slate-500 font-medium text-sm line-clamp-2 max-w-3xl leading-relaxed">{assignment.description}</p>
                    </div>

                    <div className="flex items-center gap-10 w-full lg:w-auto relative z-10 shrink-0">
                      <div className="flex-1 lg:w-64 bg-slate-50 rounded-2xl p-4 border border-slate-100">
                        <div className="flex justify-between items-center mb-3">
                          <span className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center">
                             Class Progress
                          </span>
                          <span className={`text-sm font-black px-2.5 py-1 rounded-lg ${progressPercent === 100 ? 'bg-emerald-100 text-emerald-700' : 'bg-primary-100 text-primary-700'}`}>
                            {submittedCount}/{totalStudents}
                          </span>
                        </div>
                        <div className="h-2 w-full bg-slate-200/60 rounded-full overflow-hidden shadow-inner">
                          <motion.div 
                            className={`h-full rounded-full ${progressPercent === 100 ? 'bg-emerald-500' : 'bg-primary-500'}`}
                            initial={{ width: 0 }}
                            animate={{ width: `${progressPercent}%` }}
                            transition={{ duration: 1, ease: 'easeOut' }}
                          />
                        </div>
                      </div>

                      <button className={`w-12 h-12 flex-shrink-0 rounded-full flex items-center justify-center transition-all duration-300 ${isExpanded ? 'bg-slate-900 text-white rotate-180' : 'bg-white border border-slate-200 shadow-sm text-slate-400 hover:bg-slate-50 hover:text-slate-700'}`}>
                        <ChevronDown size={24} />
                      </button>
                    </div>
                  </div>

                  <AnimatePresence>
                    {isExpanded && (
                      <motion.div 
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        className="border-t border-slate-100 bg-slate-50/50 p-8 overflow-hidden"
                      >
                        <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-2">
                          <Users size={14} /> Student Analytics
                        </h4>

                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                          {students.map(student => {
                            const sub = assignment.submissions.find(s => s.studentId === student.id);
                            const isSubmitted = sub && sub.status === 'submitted';

                            return (
                              <motion.div whileHover={{ scale: 1.02 }} key={student.id} className="bg-white p-4 rounded-xl border border-slate-200 flex items-center justify-between shadow-sm">
                                <div className="flex flex-wrap items-center gap-3">
                                   <div className={`w-10 h-10 rounded-full flex items-center justify-center text-sm font-black ${isSubmitted ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-500'}`}>
                                     {student.name.charAt(0)}
                                   </div>
                                   <span className={`font-bold text-sm ${isSubmitted ? 'text-slate-900' : 'text-slate-600'}`}>{student.name}</span>
                                </div>

                                {isSubmitted ? (
                                  <div className="text-emerald-500 p-2">
                                    <CheckCircle2 size={22} />
                                  </div>
                                ) : (
                                  <div className="text-slate-300 p-2 relative">
                                    <Circle size={22} />
                                    <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-2 h-2 rounded-full bg-slate-200"></div>
                                  </div>
                                )}
                              </motion.div>
                            );
                          })}
                        </div>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </motion.div>
              );
            })
          )}
        </motion.div>
      </div>
    </motion.div>
  );
};

export default AdminDashboard;

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { saveAssignment } from '../../utils/localStorage';
import { useAuth } from '../../context/AuthContext';
import { ArrowLeft, Send, Link as LinkIcon, FileText, Calendar } from 'lucide-react';
import { motion } from 'framer-motion';
import toast from 'react-hot-toast';

const CreateAssignment = () => {
  const navigate = useNavigate();
  const { user } = useAuth();

  const [formData, setFormData] = useState({
    title: '',
    description: '',
    driveLink: '',
    dueDate: ''
  });

  const [errors, setErrors] = useState({});

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
  };

  const validate = () => {
    const newErrors = {};
    if (!formData.title.trim()) newErrors.title = 'Title is required';
    if (!formData.description.trim()) newErrors.description = 'Description is required';
    if (!formData.dueDate) newErrors.dueDate = 'Due date is required';

    if (formData.driveLink && !/^https?:\/\//.test(formData.driveLink)) {
      newErrors.driveLink = 'Link must start with http:// or https://';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!validate()) {
      toast.error('Please fix the errors in the form.');
      return;
    }

    const newAssignment = {
      id: `assign_${Date.now()}`,
      title: formData.title,
      description: formData.description,
      driveLink: formData.driveLink,
      createdBy: user.id,
      dueDate: new Date(formData.dueDate).toISOString(),
      createdAt: new Date().toISOString()
    };

    saveAssignment(newAssignment);
    toast.success('Assignment published successfully!');
    navigate('/admin');
  };

  // Get tomorrow's date for the min date picker
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const minDate = tomorrow.toISOString().split('T')[0];

  return (
    <motion.div initial={{ opacity: 0, y: 15 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.4 }} className="max-w-2xl mx-auto space-y-6">
      <Link to="/admin" className="inline-flex items-center text-sm font-bold text-slate-500 hover:text-primary-600 transition-colors mb-2 uppercase tracking-wide">
        <ArrowLeft size={16} className="mr-1" /> Back to Dashboard
      </Link>

      <div>
        <h2 className="text-3xl font-bold text-slate-900 mb-2">Create New Assignment</h2>
        <p className="text-slate-500">Fill in the details below to assign tasks to your students.</p>
      </div>

      <div className="bg-white rounded-3xl p-8 border border-slate-200 shadow-sm relative overflow-hidden">
        <form onSubmit={handleSubmit} className="space-y-6 relative z-10">

          {/* Title */}
          <div>
            <label htmlFor="title" className="block text-sm font-semibold text-slate-700 mb-2">
              Assignment Title *
            </label>
            <div className="relative">
              <input
                type="text"
                id="title"
                name="title"
                value={formData.title}
                onChange={handleChange}
                placeholder="e.g. Variables and Data Types in JS"
                className={`w-full px-4 py-3 rounded-xl border focus:ring-2 focus:outline-none transition-colors ${
                  errors.title ? 'border-rose-300 focus:ring-rose-200 focus:border-rose-400 bg-rose-50/30' : 'border-slate-200 focus:ring-primary-100 focus:border-primary-400 bg-slate-50'
                }`}
              />
            </div>
            {errors.title && <p className="mt-1.5 text-sm text-rose-500">{errors.title}</p>}
          </div>

          {/* Description */}
          <div>
            <label htmlFor="description" className="block text-sm font-semibold text-slate-700 mb-2 flex items-center">
              <FileText size={16} className="mr-1.5 text-slate-400" /> Instructions *
            </label>
            <textarea
              id="description"
              name="description"
              rows={5}
              value={formData.description}
              onChange={handleChange}
              placeholder="Describe what needs to be done..."
              className={`w-full px-4 py-3 rounded-xl border focus:ring-2 focus:outline-none transition-colors resize-y ${
                errors.description ? 'border-rose-300 focus:ring-rose-200 focus:border-rose-400 bg-rose-50/30' : 'border-slate-200 focus:ring-primary-100 focus:border-primary-400 bg-slate-50'
              }`}
            />
            {errors.description && <p className="mt-1.5 text-sm text-rose-500">{errors.description}</p>}
          </div>

          {/* Due Date & Drive Link */}
          <div className="grid md:grid-cols-2 gap-6">
            <div>
              <label htmlFor="dueDate" className="block text-sm font-semibold text-slate-700 mb-2 flex items-center">
                <Calendar size={16} className="mr-1.5 text-slate-400" /> Due Date *
              </label>
              <input
                type="date"
                id="dueDate"
                name="dueDate"
                min={minDate}
                value={formData.dueDate}
                onChange={handleChange}
                className={`w-full px-4 py-3 rounded-xl border focus:ring-2 focus:outline-none transition-colors ${
                  errors.dueDate ? 'border-rose-300 focus:ring-rose-200 focus:border-rose-400 bg-rose-50/30' : 'border-slate-200 focus:ring-primary-100 focus:border-primary-400 bg-slate-50'
                }`}
              />
              {errors.dueDate && <p className="mt-1.5 text-sm text-rose-500">{errors.dueDate}</p>}
            </div>

            <div>
              <label htmlFor="driveLink" className="block text-sm font-semibold text-slate-700 mb-2 flex items-center">
                <LinkIcon size={16} className="mr-1.5 text-slate-400" /> External Link <span className="text-slate-400 font-normal ml-1">(Optional)</span>
              </label>
              <input
                type="text"
                id="driveLink"
                name="driveLink"
                value={formData.driveLink}
                onChange={handleChange}
                placeholder="Google Drive, Github, etc."
                className={`w-full px-4 py-3 rounded-xl border focus:ring-2 focus:outline-none transition-colors ${
                  errors.driveLink ? 'border-rose-300 focus:ring-rose-200 focus:border-rose-400 bg-rose-50/30' : 'border-slate-200 focus:ring-primary-100 focus:border-primary-400 bg-slate-50'
                }`}
              />
              {errors.driveLink && <p className="mt-1.5 text-sm text-rose-500">{errors.driveLink}</p>}
            </div>
          </div>

          <div className="pt-6 border-t border-slate-100 flex justify-end">
            <button
              type="submit"
              className="flex items-center px-6 py-3 bg-slate-900 hover:bg-slate-800 text-white font-medium rounded-xl transition-all shadow-md hover:shadow-lg transform hover:-translate-y-0.5"
            >
              <Send size={18} className="mr-2" /> Publish Assignment
            </button>
          </div>
        </form>
      </div>
    </motion.div>
  );
};

export default CreateAssignment;

