import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getAssignments, getStudentSubmissions, saveSubmission } from '../../utils/localStorage';
import { useAuth } from '../../context/AuthContext';
import { ArrowLeft, Clock, Calendar, CheckCircle2, Link as LinkIcon, FileText, UploadCloud, ChevronRight, AlertCircle, Sparkles } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import toast from 'react-hot-toast';

const AssignmentDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [assignment, setAssignment] = useState(null);
  const [status, setStatus] = useState('pending');
  const [showConfirmModal, setShowConfirmModal] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    const all = getAssignments();
    const current = all.find(a => a.id === id);
    if (!current) {
      navigate('/student');
      return;
    }
    setAssignment(current);

    const subs = getStudentSubmissions(user.id);
    const mySub = subs.find(s => s.assignmentId === id);
    if (mySub) {
      setStatus(mySub.status);
    }
  }, [id, user.id, navigate]);

  const handleFinalSubmit = () => {
    setIsSubmitting(true);

    // Save to database immediately to prevent race conditions 
    // if the user closes/refreshes before the premium delay finishes
    saveSubmission({
      id: `sub_${Date.now()}`,
      assignmentId: id,
      studentId: user.id,
      status: 'submitted',
      submittedAt: new Date().toISOString()
    });

    // Simulate network delay for premium feel
    setTimeout(() => {
      setStatus('submitted');
      setIsSubmitting(false);
      setShowConfirmModal(false);
      toast.success('Assignment submitted successfully!', { icon: '≡ƒÄô' });
    }, 1500);
  };

  if (!assignment) return null;

  const isComplete = status === 'submitted';

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="max-w-4xl mx-auto pb-12">

      {/* Premium Back Navigation */}
      <motion.button 
        initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: 0.1 }}
        onClick={() => navigate('/student')} 
        className="inline-flex items-center gap-2 text-sm font-bold text-slate-500 hover:text-slate-900 transition-colors mb-8 group uppercase tracking-widest pl-1"
      >
        <div className="w-8 h-8 rounded-full bg-white border border-slate-200 flex items-center justify-center group-hover:bg-slate-100 transition-colors shadow-sm">
           <ArrowLeft size={16} className="transform group-hover:-translate-x-0.5 transition-transform" /> 
        </div>
        Back to Dashboard
      </motion.button>

      {/* Main Content Card */}
      <motion.div 
        initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2, type: "spring", stiffness: 300, damping: 25 }}
        className="bg-white rounded-[2.5rem] p-8 md:p-12 border border-slate-200 shadow-xl relative overflow-hidden"
      >
        {/* Abstract Corner Blob */}
        {isComplete ? (
          <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/10 rounded-full mix-blend-multiply filter blur-3xl transform translate-x-1/2 -translate-y-1/2 pointer-events-none"></div>
        ) : (
          <div className="absolute top-0 right-0 w-64 h-64 bg-primary-500/10 rounded-full mix-blend-multiply filter blur-3xl transform translate-x-1/2 -translate-y-1/2 pointer-events-none"></div>
        )}

        <div className="flex flex-col md:flex-row md:items-start justify-between gap-6 mb-10 relative z-10">
          <div className="flex-1">
            <div className="flex items-center gap-3 mb-4">
              {isComplete ? (
                <span className="inline-flex items-center px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest bg-emerald-100 text-emerald-700">
                  <CheckCircle2 size={14} className="mr-2" /> Completed
                </span>
              ) : (
                <span className="inline-flex items-center px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest bg-slate-100 text-slate-600">
                  <Clock size={14} className="mr-2" /> Pending Submission
                </span>
              )}
            </div>
            <h1 className="text-4xl md:text-5xl font-black text-slate-900 tracking-tight leading-tight mb-4">
              {assignment.title}
            </h1>
          </div>
        </div>

        {/* Info Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-12 relative z-10">
          <div className="bg-slate-50 rounded-3xl p-6 border border-slate-100 flex items-start gap-4 hover:bg-slate-100/80 transition-colors">
            <div className="w-12 h-12 rounded-2xl bg-white border border-slate-200 shadow-sm flex items-center justify-center shrink-0 text-primary-500">
              <Calendar size={24} />
            </div>
            <div>
              <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Due Date</p>
              <p className="text-lg font-bold text-slate-900">{new Date(assignment.dueDate).toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
              <p className="text-sm font-semibold text-slate-500 mt-0.5">at 11:59 PM</p>
            </div>
          </div>

          <div className="bg-slate-50 rounded-3xl p-6 border border-slate-100 flex items-start gap-4 hover:bg-slate-100/80 transition-colors">
            <div className="w-12 h-12 rounded-2xl bg-white border border-slate-200 shadow-sm flex items-center justify-center shrink-0 text-blue-500">
              <Sparkles size={24} />
            </div>
            <div>
              <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Instructor</p>
              <p className="text-lg font-bold text-slate-900">Dr. Smith</p>
              <p className="text-sm font-semibold text-slate-500 mt-0.5">Computer Science Dept.</p>
            </div>
          </div>
        </div>

        <div className="prose prose-slate max-w-none relative z-10">
          <h3 className="text-xl font-bold flex items-center gap-2 mb-4">
            <FileText size={20} className="text-primary-500" /> Instructions
          </h3>
          <div className="bg-white border border-slate-200 shadow-sm rounded-3xl p-8 mb-10 text-slate-600 font-medium leading-relaxed text-lg whitespace-pre-wrap">
            {assignment.description}
          </div>
        </div>

        {assignment.driveLink && (
           <div className="mb-12 relative z-10">
             <h3 className="text-xl font-bold flex items-center gap-2 mb-4">
               <LinkIcon size={20} className="text-blue-500" /> Reference Material
             </h3>
             <a 
               href={assignment.driveLink} 
               target="_blank" 
               rel="noopener noreferrer"
               className="group flex flex-col sm:flex-row sm:items-center justify-between p-6 bg-blue-50/50 hover:bg-blue-50 border border-blue-100 rounded-3xl transition-all duration-300 shadow-sm"
             >
               <div className="flex items-center gap-4 mb-4 sm:mb-0">
                 <div className="w-12 h-12 rounded-2xl bg-blue-100 text-blue-600 flex items-center justify-center shadow-inner">
                   <UploadCloud size={24} />
                 </div>
                 <div>
                   <span className="block font-bold text-slate-900 group-hover:text-blue-700 transition-colors">Google Drive Shared Folder</span>
                   <span className="text-sm font-semibold text-slate-500">Access required resources here</span>
                 </div>
               </div>
               <div className="flex items-center font-bold text-blue-600 text-sm tracking-wide uppercase px-4 py-2 bg-white rounded-xl shadow-sm border border-blue-100 group-hover:shadow group-hover:-translate-y-0.5 transition-all">
                 Open Resource <ChevronRight size={16} className="ml-1" />
               </div>
             </a>
           </div>
        )}

        {/* Action Area */}
        <div className="pt-8 border-t border-slate-100 relative z-10">
          {isComplete ? (
            <div className="bg-emerald-50 border border-emerald-200 rounded-3xl p-8 text-center shadow-inner shadow-emerald-100/50">
              <div className="w-20 h-20 bg-emerald-100 rounded-full flex items-center justify-center mx-auto mb-5">
                <CheckCircle2 size={40} className="text-emerald-500" />
              </div>
              <h3 className="text-2xl font-black text-emerald-900 mb-2">Work Submitted</h3>
              <p className="text-emerald-700 font-medium text-lg">Your assignment has been recorded successfully. Great job!</p>
            </div>
          ) : (
             <div className="flex flex-col sm:flex-row items-center justify-between gap-6 bg-slate-50 p-6 rounded-3xl border border-slate-200">
                <div className="flex items-center gap-4 text-slate-500">
                   <AlertCircle size={24} className="text-orange-400" />
                   <p className="font-semibold text-sm max-w-xs">Make sure you have uploaded all your files to the provided Drive link before confirming submission.</p>
                </div>
                <motion.button 
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.97 }}
                  onClick={() => setShowConfirmModal(true)}
                  className="w-full sm:w-auto flex items-center justify-center gap-3 px-8 py-4 bg-primary-600 hover:bg-primary-700 text-white font-bold rounded-2xl shadow-xl shadow-primary-500/30 transition-all uppercase tracking-widest text-sm shrink-0"
                >
                  <CheckCircle2 size={18} />
                  Mark as Submitted
                </motion.button>
             </div>
          )}
        </div>
      </motion.div>

      {/* Ultra-Premium Modal */}
      <AnimatePresence>
        {showConfirmModal && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center p-4 md:p-6"
          >
            <motion.div 
              initial={{ scale: 0.9, opacity: 0, y: 30 }}
              animate={{ scale: 1, opacity: 1, y: 0 }}
              exit={{ scale: 0.9, opacity: 0, y: 30 }}
              transition={{ type: "spring", stiffness: 400, damping: 30 }}
              className="bg-white rounded-[2.5rem] max-w-lg w-full shadow-2xl overflow-hidden relative"
            >
              {/* Spinning decorative background */}
              {isSubmitting && (
                <motion.div 
                  className="absolute -top-[50%] -left-[50%] w-[200%] h-[200%] bg-[conic-gradient(transparent_0deg,transparent_270deg,theme(colors.primary.500)_360deg)] z-0 rounded-full"
                  animate={{ rotate: 360 }}
                  transition={{ duration: 2, repeat: Infinity, ease: "linear" }}
                />
              )}

              <div className="bg-white m-1 rounded-[2.4rem] relative z-10 h-[calc(100%-8px)] p-10 flex flex-col items-center text-center">
                <div className={`w-20 h-20 rounded-3xl flex items-center justify-center mx-auto mb-6 transform transition-all duration-500 ${isSubmitting ? 'bg-primary-50 scale-110' : 'bg-slate-50 rotate-3'}`}>
                  {isSubmitting ? (
                    <motion.div
                      animate={{ rotate: 360 }}
                      transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
                      className="w-8 h-8 rounded-full border-4 border-primary-500 border-t-transparent"
                    />
                  ) : (
                    <UploadCloud size={40} className="text-blue-500 transform -rotate-3" />
                  )}
                </div>

                <h3 className="text-3xl font-black text-slate-900 mb-3 tracking-tight">
                  {isSubmitting ? "Submitting Work..." : "Confirm Submission"}
                </h3>

                <p className="text-slate-500 mb-10 font-medium text-lg px-4 leading-relaxed">
                  {isSubmitting 
                    ? "Securing your work with cryptographic hashes." 
                    : <>Are you sure you want to submit your work for <span className="font-bold text-slate-800">"{assignment.title}"</span>? This action is permanent.</>
                  }
                </p>

                <div className="w-full flex flex-col gap-3 mt-auto">
                  <button 
                    disabled={isSubmitting}
                    onClick={handleFinalSubmit}
                    className="w-full flex justify-center items-center py-4 px-6 bg-slate-900 hover:bg-black text-white rounded-2xl font-bold transition-all shadow-xl hover:shadow-2xl disabled:opacity-50 disabled:cursor-not-allowed uppercase tracking-widest text-sm relative overflow-hidden group"
                  >
                    <span className="relative z-10 flex items-center">
                      <CheckCircle2 size={18} className="mr-2" />
                      {isSubmitting ? "Processing..." : "Yes, I have submitted"}
                    </span>
                    {!isSubmitting && <div className="absolute inset-0 bg-white/20 transform translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>}
                  </button>
                  <button 
                    disabled={isSubmitting}
                    onClick={() => setShowConfirmModal(false)}
                    className="w-full py-4 px-6 bg-white border border-slate-200 hover:bg-slate-50 text-slate-600 rounded-2xl font-bold transition-colors disabled:opacity-50 uppercase tracking-widest text-sm"
                  >
                    Cancel
                  </button>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export default AssignmentDetails;

