import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { getAssignments, getStudentSubmissions } from '../../utils/localStorage';
import { Link } from 'react-router-dom';
import { Calendar, CheckCircle2, Circle, Clock, ChevronRight, Sparkles, BookOpen, AlertCircle, ListFilter } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const FILTERS = ['All', 'Pending', 'Submitted'];

const StudentDashboard = () => {
  const { user } = useAuth();
  const [assignments, setAssignments] = useState([]);
  const [submissions, setSubmissions] = useState([]);
  const [activeFilter, setActiveFilter] = useState('All');

  useEffect(() => {
    const allAssignments = getAssignments();
    allAssignments.sort((a, b) => new Date(a.dueDate) - new Date(b.dueDate));
    setAssignments(allAssignments);
    setSubmissions(getStudentSubmissions(user.id));
  }, [user.id]);

  const getSubmissionStatus = (id) => submissions.find(s => s.assignmentId === id)?.status || 'pending';

  const completedCount = assignments.filter(a => getSubmissionStatus(a.id) === 'submitted').length;
  const pendingCount = assignments.filter(a => getSubmissionStatus(a.id) !== 'submitted').length;
  const totalCount = assignments.length;
  const progressPercent = totalCount === 0 ? 0 : Math.round((completedCount / totalCount) * 100);

  // Filtered assignments based on active tab
  const filteredAssignments = assignments.filter(a => {
    const submitted = getSubmissionStatus(a.id) === 'submitted';
    if (activeFilter === 'Submitted') return submitted;
    if (activeFilter === 'Pending') return !submitted;
    return true;
  });

  const filterCounts = {
    All: totalCount,
    Pending: pendingCount,
    Submitted: completedCount,
  };

  const getDaysRemainingInfo = (dueDateString) => {
    if (!dueDateString) return { text: 'No due date', urgent: false };
    const dueDate = new Date(dueDateString);
    if (isNaN(dueDate.getTime())) return { text: 'Unknown date', urgent: false };
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const targetDate = new Date(dueDate.getTime());
    targetDate.setHours(0, 0, 0, 0);
    const diffTime = targetDate.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    if (diffDays < 0) return { text: 'Overdue', urgent: true };
    if (diffDays === 0) return { text: 'Due today', urgent: true };
    if (diffDays === 1) return { text: 'Due tomorrow', urgent: true };
    return { text: `${diffDays} days left`, urgent: diffDays <= 3 };
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    show: { opacity: 1, transition: { staggerChildren: 0.08 } }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    show: { opacity: 1, y: 0, transition: { type: "spring", stiffness: 300, damping: 24 } }
  };

  return (
    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.5 }} className="space-y-10 font-sans">

      {/* Header Area */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: 0.1 }} className="flex items-center gap-2 mb-2">
            <Sparkles className="text-primary-500 w-5 h-5" />
            <span className="text-primary-600 font-bold uppercase tracking-widest text-sm">Dashboard Overview</span>
          </motion.div>
          <h2 className="text-3xl sm:text-4xl lg:text-5xl font-black text-slate-900 tracking-tight leading-tight">
            Welcome back, <br className="md:hidden" />
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary-600 to-emerald-500">{user.name.split(' ')[0]}</span>
          </h2>
        </div>
      </div>

      {/* Hero Progress Banner */}
      <motion.div 
        initial={{ opacity: 0, scale: 0.98, y: 10 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        transition={{ delay: 0.2, type: 'spring', bounce: 0.3 }}
        className="relative overflow-hidden bg-slate-900 rounded-[1.5rem] sm:rounded-[2rem] p-6 sm:p-8 md:p-12 shadow-2xl"
      >
        <div className="absolute top-0 right-0 w-[40rem] h-[40rem] bg-gradient-to-br from-primary-500/30 via-blue-500/20 to-transparent rounded-full mix-blend-screen filter blur-[80px] -translate-y-1/2 translate-x-1/3 animate-blob"></div>
        <div className="absolute bottom-0 left-0 w-[30rem] h-[30rem] bg-gradient-to-tr from-emerald-500/20 to-transparent rounded-full mix-blend-screen filter blur-[60px] translate-y-1/3 -translate-x-1/4 animate-blob animation-delay-2000"></div>

        <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-10">
          <div className="max-w-xl">
            <h3 className="text-2xl md:text-3xl font-bold text-white mb-3 tracking-tight">Your Academic Progress</h3>
            <p className="text-slate-300 text-base sm:text-lg leading-relaxed">
              You have completed <strong className="text-white font-black">{completedCount}</strong> out of <strong className="text-white font-black">{totalCount}</strong> assignments. Keep up the phenomenal work!
            </p>

            {/* Quick stat pills */}
            <div className="flex items-center gap-3 mt-5 flex-wrap">
              <div className="flex items-center gap-2 bg-emerald-500/20 border border-emerald-500/30 px-3 py-1.5 rounded-full">
                <CheckCircle2 size={13} className="text-emerald-400" />
                <span className="text-emerald-300 font-bold text-xs sm:text-sm">{completedCount} Submitted</span>
              </div>
              <div className="flex items-center gap-2 bg-white/10 border border-white/10 px-3 py-1.5 rounded-full">
                <Clock size={13} className="text-slate-400" />
                <span className="text-slate-300 font-bold text-xs sm:text-sm">{pendingCount} Pending</span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-4 sm:gap-6 bg-white/10 backdrop-blur-xl border border-white/20 p-4 sm:p-6 rounded-2xl sm:rounded-3xl shrink-0">
            <div className="relative flex items-center justify-center w-20 h-20 sm:w-28 sm:h-28 shrink-0">
              <svg className="w-full h-full transform -rotate-90" viewBox="0 0 100 100">
                <circle cx="50" cy="50" r="45" fill="none" stroke="rgba(255,255,255,0.1)" strokeWidth="8" />
                <motion.circle 
                  cx="50" cy="50" r="45" 
                  fill="none" stroke="url(#progress-gradient)" 
                  strokeWidth="8"
                  strokeLinecap="round"
                  strokeDasharray={`${2 * Math.PI * 45}`}
                  initial={{ strokeDashoffset: 2 * Math.PI * 45 }}
                  animate={{ strokeDashoffset: (2 * Math.PI * 45) * (1 - progressPercent / 100) }}
                  transition={{ duration: 1.5, ease: 'easeOut', delay: 0.5 }}
                />
                <defs>
                  <linearGradient id="progress-gradient" x1="0%" y1="0%" x2="100%" y2="0%">
                    <stop offset="0%" stopColor="#34d399" />
                    <stop offset="100%" stopColor="#10b981" />
                  </linearGradient>
                </defs>
              </svg>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-3xl font-black text-white">{progressPercent}%</span>
              </div>
            </div>

            <div className="hidden sm:block">
              <p className="text-white font-bold text-xl mb-1">Completion</p>
              <p className="text-emerald-400 font-semibold flex items-center gap-1.5 text-sm uppercase tracking-widest">
                <CheckCircle2 size={16} /> Status
              </p>
            </div>
          </div>
        </div>
      </motion.div>

      {/* Assignment Grid */}
      <div>
        {/* Section Header + Filter Tabs */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6">
          <div className="flex items-center gap-3">
            <h3 className="text-2xl font-bold text-slate-900 tracking-tight">My Assignments</h3>
            <span className="bg-slate-200 text-slate-700 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest">{filteredAssignments.length} Shown</span>
          </div>

          {/* ΓÇöΓÇöΓÇö FILTER TABS ΓÇöΓÇöΓÇö */}
          <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-2xl border border-slate-200 self-start">
            <ListFilter size={16} className="text-slate-400 ml-2 hidden sm:block" />
            {FILTERS.map(filter => (
              <button
                key={filter}
                onClick={() => setActiveFilter(filter)}
                className={`relative px-4 py-2 rounded-xl text-sm font-bold transition-all duration-200 ${
                  activeFilter === filter ? 'text-slate-900' : 'text-slate-500 hover:text-slate-800'
                }`}
              >
                {activeFilter === filter && (
                  <motion.div
                    layoutId="filter-pill"
                    className="absolute inset-0 bg-white rounded-xl shadow-sm border border-slate-200"
                    transition={{ type: 'spring', stiffness: 500, damping: 35 }}
                  />
                )}
                <span className="relative z-10 flex items-center gap-2">
                  {filter}
                  <span className={`text-[10px] font-black px-1.5 py-0.5 rounded-full ${
                    activeFilter === filter
                      ? filter === 'Submitted' ? 'bg-emerald-100 text-emerald-700'
                        : filter === 'Pending' ? 'bg-rose-100 text-rose-600'
                        : 'bg-primary-100 text-primary-700'
                      : 'bg-slate-200 text-slate-500'
                  }`}>
                    {filterCounts[filter]}
                  </span>
                </span>
              </button>
            ))}
          </div>
        </div>

        <AnimatePresence mode="wait">
          <motion.div
            key={activeFilter}
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -10 }}
            transition={{ duration: 0.2 }}
          >
            <motion.div variants={containerVariants} initial="hidden" animate="show" className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {filteredAssignments.length === 0 ? (
                <motion.div variants={itemVariants} className="md:col-span-2 flex flex-col items-center justify-center p-20 bg-white rounded-3xl border border-dashed border-slate-300 shadow-sm relative overflow-hidden">
                  <div className="absolute inset-0 bg-slate-50/50"></div>
                  <div className="relative z-10 flex flex-col items-center">
                    <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-6">
                      {activeFilter === 'Submitted' ? (
                        <CheckCircle2 className="w-10 h-10 text-slate-400" />
                      ) : (
                        <BookOpen className="w-10 h-10 text-slate-400" />
                      )}
                    </div>
                    <h3 className="text-2xl font-bold text-slate-900 mb-2">
                      {activeFilter === 'Submitted' ? 'No submissions yet' : activeFilter === 'Pending' ? "You're all caught up!" : 'No assignments yet'}
                    </h3>
                    <p className="text-slate-500 font-medium text-center max-w-sm">
                      {activeFilter === 'Submitted'
                        ? 'Submit an assignment and it will appear here.'
                        : activeFilter === 'Pending'
                        ? 'All assignments have been submitted. Great job!'
                        : 'There are no assignments at the moment.'}
                    </p>
                  </div>
                </motion.div>
              ) : (
                filteredAssignments.map((assignment) => {
                  const status = getSubmissionStatus(assignment.id);
                  const isSubmitted = status === 'submitted';
                  const timeInfo = getDaysRemainingInfo(assignment.dueDate);

                  return (
                    <motion.div variants={itemVariants} key={assignment.id} className="relative group h-full cursor-pointer">
                      <div className={`absolute -inset-0.5 rounded-3xl bg-gradient-to-br transition-opacity duration-300 opacity-0 group-hover:opacity-100 pointer-events-none ${isSubmitted ? 'from-emerald-300 to-teal-400 blur-sm' : 'from-blue-300 to-indigo-400 blur-sm'}`}></div>

                      <Link 
                        to={`/student/assignment/${assignment.id}`} 
                        className={`relative flex flex-col h-full p-7 rounded-[1.5rem] border transition-all duration-300 shadow-sm group-hover:shadow-xl bg-white ${
                          isSubmitted ? 'border-emerald-100' : 'border-slate-200'
                        }`}
                      >
                        <div className="flex justify-between items-start mb-5">
                          <div className={`p-3 rounded-2xl ${isSubmitted ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-50 text-slate-400 group-hover:bg-blue-50 group-hover:text-blue-600'} transition-colors`}>
                            {isSubmitted ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                          </div>

                          {isSubmitted ? (
                            <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest bg-emerald-50 text-emerald-700 ring-1 ring-inset ring-emerald-600/20">
                              <CheckCircle2 size={11} className="mr-1.5" /> Submitted
                            </span>
                          ) : timeInfo.urgent ? (
                            <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest bg-rose-50 text-rose-700 ring-1 ring-inset ring-rose-600/20">
                              <AlertCircle size={12} className="mr-1.5" /> Urgent
                            </span>
                          ) : (
                            <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest bg-slate-100 text-slate-600 ring-1 ring-inset ring-slate-500/10">
                              Pending
                            </span>
                          )}
                        </div>

                        <div className="flex-1 mb-6">
                          <h4 className="text-xl font-bold text-slate-900 mb-2.5 group-hover:text-blue-700 transition-colors line-clamp-2">
                            {assignment.title}
                          </h4>
                          <p className="text-slate-500 font-medium text-sm leading-relaxed line-clamp-2">
                            {assignment.description}
                          </p>
                        </div>

                        <div className="flex items-center justify-between pt-5 border-t border-slate-100">
                          <div className={`flex items-center gap-2 text-sm font-bold uppercase tracking-widest ${
                            isSubmitted ? 'text-emerald-500' : 
                            timeInfo.urgent ? 'text-rose-600' : 'text-slate-500'
                          }`}>
                            {isSubmitted ? <CheckCircle2 size={16} /> : <Clock size={16} />}
                            {isSubmitted ? 'Done' : timeInfo.text}
                          </div>

                          <div className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center text-slate-400 group-hover:bg-blue-600 group-hover:text-white transition-all transform group-hover:scale-110">
                            <ChevronRight size={20} className="transform group-hover:translate-x-0.5 transition-transform" />
                          </div>
                        </div>
                      </Link>
                    </motion.div>
                  )
                })
              )}
            </motion.div>
          </motion.div>
        </AnimatePresence>
      </div>
    </motion.div>
  );
};

export default StudentDashboard;
